    let tools_arr = body["tools"]
        .as_array()
        .expect("body must contain 'tools' array");
    assert_eq!(tools_arr.len(), 1);
    assert_eq!(tools_arr[0]["type"], "function");
    assert_eq!(tools_arr[0]["function"]["name"], "create_skill");
}

