    // Done event with usage.
    let done = events
        .iter()
        .find_map(|e| match e {
            StreamEvent::Done(u) => Some(u),
            _ => None,
        })
        .expect("stream must emit Done");
    assert_eq!(done.input_tokens, 42);
    assert_eq!(done.output_tokens, 18);
}

