                .iter()
                .any(|e| matches!(e, StreamEvent::ToolCallArgumentsDelta { .. }))
        );
        assert!(
            events
                .iter()
                .any(|e| matches!(e, StreamEvent::ToolCallComplete { index } if *index == 0))
        );
        assert!(events.iter().any(|e| matches!(e, StreamEvent::Done(_))));
    }

